def check_number(num):
    if num > 0:
        return 'Positive'
    else:
        return 'Not Positive'

def temperature_check(temp):
    if temp <= 0:
        return 'Freezing'
    elif temp <= 15:
        return 'Cold'
    elif temp <= 25:
        return 'Warm'
    else:
        return 'Hot'

def even_or_odd(num):
    if num > 0:
        if num % 2 == 0:
            return 'Positive Even'
        else:
            return 'Positive Odd'
    else:
        if num % 2 == 0:
            return 'Negative Even'
        else:
            return 'Negative Odd'
